solutions.cpp:
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void reverseStack(vector<int>& s) {
        if (!s.empty()) {
            int top = s.back();
            s.pop_back();
            reverseStack(s);
            insertAtBottom(s, top);
        }
    }
private:
    void insertAtBottom(vector<int>& s, int item) {
        if (s.empty()) {
            s.push_back(item);
            return;
        }
        int top = s.back();
        s.pop_back();
        insertAtBottom(s, item);
        s.push_back(top);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> stack(n);
    for (int i = 0; i < n; ++i) cin >> stack[i];
    Solution sol;
    sol.reverseStack(stack);
    for (int val : stack) {
        cout << val << "\n";
    }
    return 0;
}
